import { resolve } from 'node:path';
import { writeFileSync } from 'node:fs';

/**
 * Generate _observer.ts — connects all observers to pubsub.
 *
 * Each observer in config.observers[] receives events from the runtime
 * and can send control plane requests back over pubsub.
 */
export function generateObserver(generatedDir: string) {
  const lines = [
    '// AUTO-GENERATED by interactkit build — do not edit',
    '// Connects all observers to pubsub for event streaming and control plane.',
    "import type { InteractKitConfig } from '@interactkit/sdk';",
    "import type { BaseObserver } from '@interactkit/sdk';",
    "import _config from './interactkit.config.js';",
    "const config = _config as InteractKitConfig;",
    '',
    'const observers = (config.observers ?? []) as BaseObserver[];',
    '',
    'for (const observer of observers) {',
    '  await observer.connect(config.pubsub);',
    '}',
    '',
    'if (observers.length > 0) {',
    `  console.log(\`▸ \${observers.length} observer(s) connected\`);`,
    '}',
    '',
  ];

  writeFileSync(resolve(generatedDir, '_observer.ts'), lines.join('\n'), 'utf-8');
}
